import modal

app = modal.App("fastapi-json-transform")

# Define the Modal image with FastAPI installed
image = modal.Image.debian_slim().pip_install("fastapi")


@app.function(image=image)
@modal.asgi_app()
def fastapi_app():
    from fastapi import FastAPI

    fastapi = FastAPI()

    @fastapi.get("/")
    def read_root():
        return {"status": "ok", "service": "json-transform"}

    @fastapi.post("/transform")
    def transform(request: dict):
        data = request.get("data", [])
        operation = request.get("operation", "")

        if operation == "reverse":
            result = list(reversed(data))
        elif operation == "sort":
            result = sorted(data)
        else:
            result = data

        return {"result": result}

    return fastapi


@app.local_entrypoint()
def main():
    # Get the deployed endpoint URL
    url = fastapi_app.url

    # Make a health check request to verify the endpoint is working
    import httpx

    try:
        response = httpx.get(f"{url}/")
        response.raise_for_status()
        health_check_result = "ok"
    except Exception as e:
        health_check_result = f"failed: {str(e)}"

    # Store results in Modal Dict
    output_dict = modal.Dict.from_name("fastapi-json-transform-output", create_if_missing=True)
    output_dict["health_check"] = health_check_result
    output_dict["endpoint_deployed"] = True

    print(f"Health check: {health_check_result}")
    print(f"Endpoint deployed at: {url}")
